class Solution(object):
    def canReachCorner(self, xCorner, yCorner, circles):
        """
        :type xCorner: int
        :type yCorner: int
        :type circles: List[List[int]]
        :rtype: bool
        """
        from math import sqrt

        # Graph approach: vertices are circles + 4 edges
        # Check if blocking obstacle reaches opposite corners

        n = len(circles)
        # Vertices: 0..n-1 = circles, n = left, n+1 = bottom, n+2 = right, n+3 = top

        def touches_edge(cx, cy, r, edge):
            if edge == 0:  # left (x=0)
                return cx - r <= 0
            elif edge == 1:  # bottom (y=0)
                return cy - r <= 0
            elif edge == 2:  # right (x=xCorner)
                return xCorner - cx <= r
            else:  # top (y=yCorner)
                return yCorner - cy <= r

        def circles_intersect(i, j):
            x1, y1, r1 = circles[i]
            x2, y2, r2 = circles[j]
            dist_sq = (x1 - x2) ** 2 + (y1 - y2) ** 2
            return dist_sq <= (r1 + r2) ** 2

        # Build adjacency
        adj = [[] for _ in range(n + 4)]

        # Circle to circle
        for i in range(n):
            for j in range(i + 1, n):
                if circles_intersect(i, j):
                    adj[i].append(j)
                    adj[j].append(i)

        # Circle to edges
        for i in range(n):
            cx, cy, r = circles[i]
            for edge in range(4):
                if touches_edge(cx, cy, r, edge):
                    adj[i].append(n + edge)
                    adj[n + edge].append(i)

        # BFS: check if left connects to right OR bottom connects to top
        from collections import deque

        def bfs(start, end):
            visited = [False] * (n + 4)
            queue = deque([start])
            visited[start] = True

            while queue:
                u = queue.popleft()
                if u == end:
                    return True
                for v in adj[u]:
                    if not visited[v]:
                        visited[v] = True
                        queue.append(v)

            return False

        # Path blocked if left-right OR bottom-top connected
        left_right_blocked = bfs(n, n + 2)  # left to right
        bottom_top_blocked = bfs(n + 1, n + 3)  # bottom to top

        return not (left_right_blocked or bottom_top_blocked)
